import React, { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { Oportunidade } from '../types';

const OportunidadesList: React.FC = () => {
  const { user } = useAuth();
  const [oportunidades, setOportunidades] = useState<Oportunidade[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchOportunidades = async () => {
      try {
        setLoading(true);
        const response = await fetch('/api/oportunidades', {
          headers: {
            'Authorization': `Bearer ${localStorage.getItem('token')}`
          }
        });

        if (!response.ok) {
          throw new Error('Erro ao carregar oportunidades');
        }

        const data = await response.json();
        setOportunidades(data);
        setLoading(false);
      } catch (error) {
        console.error('Erro:', error);
        setError('Erro ao carregar dados. Por favor, tente novamente.');
        setLoading(false);
      }
    };

    fetchOportunidades();
  }, []);

  const getBasePath = () => {
    if (user?.papel === 'instituicao_ensino') {
      return '/instituicao-ensino';
    } else if (user?.papel === 'chefe_empresa') {
      return '/chefe-empresa';
    } else if (user?.papel === 'instituicao_contratante') {
      return '/instituicao-contratante';
    }
    return '';
  };

  const handleNovaOportunidade = () => {
    navigate(`${getBasePath()}/oportunidades/nova`);
  };

  const isInstituicaoContratante = user?.papel === 'instituicao_contratante';

  return (
    <div className="container mx-auto px-4 py-8">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h1 className="text-2xl font-bold text-cursor-text-primary">Oportunidades</h1>
          <div className="text-sm text-cursor-text-secondary mt-1">
            {isInstituicaoContratante 
              ? 'Gerencie suas oportunidades oferecidas' 
              : 'Veja as oportunidades disponíveis para jovens'}
          </div>
        </div>
        {isInstituicaoContratante && (
          <button
            onClick={handleNovaOportunidade}
            className="inline-flex items-center px-4 py-2 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-cursor-primary hover:bg-cursor-primary-dark"
          >
            <svg className="-ml-1 mr-2 h-5 w-5" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M10 5a1 1 0 011 1v3h3a1 1 0 110 2h-3v3a1 1 0 11-2 0v-3H6a1 1 0 110-2h3V6a1 1 0 011-1z" clipRule="evenodd" />
            </svg>
            Nova Oportunidade
          </button>
        )}
      </div>

      <div className="bg-white rounded-lg shadow mb-8">
        <div className="p-4">
          {loading ? (
            <div className="text-center py-4">Carregando...</div>
          ) : error ? (
            <div className="text-center py-4 text-red-500">{error}</div>
          ) : oportunidades.length === 0 ? (
            <div className="text-center py-8">
              <svg className="mx-auto h-12 w-12 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" />
              </svg>
              <h3 className="mt-2 text-sm font-medium text-cursor-text-primary">Nenhuma oportunidade disponível</h3>
              {isInstituicaoContratante ? (
                <>
                  <p className="mt-1 text-sm text-cursor-text-secondary">Comece criando sua primeira oportunidade.</p>
                  <div className="mt-6">
                    <button
                      onClick={handleNovaOportunidade}
                      className="inline-flex items-center px-4 py-2 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-cursor-primary hover:bg-cursor-primary-dark focus:outline-none"
                    >
                      <svg className="-ml-1 mr-2 h-5 w-5" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M10 5a1 1 0 011 1v3h3a1 1 0 110 2h-3v3a1 1 0 11-2 0v-3H6a1 1 0 110-2h3V6a1 1 0 011-1z" clipRule="evenodd" />
                      </svg>
                      Criar Oportunidade
                    </button>
                  </div>
                </>
              ) : (
                <p className="mt-1 text-sm text-cursor-text-secondary">
                  Instituições contratantes criarão novas oportunidades em breve.
                </p>
              )}
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="min-w-full divide-y divide-gray-200">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Título</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Tipo</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Instituição</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Status</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Recomendações</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Ações</th>
                  </tr>
                </thead>
                <tbody className="bg-white divide-y divide-gray-200">
                  {oportunidades.map(oportunidade => (
                    <tr key={oportunidade.id}>
                      <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-cursor-text-primary">{oportunidade.titulo}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-cursor-text-secondary">{oportunidade.tipo}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-cursor-text-secondary">
                        {oportunidade.instituicao_nome || `Instituição #${oportunidade.instituicao_id}`}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm">
                        <span className={`px-2 py-1 text-xs rounded-full ${
                          oportunidade.status === 'Aberta' ? 'bg-green-100 text-green-800' : 
                          oportunidade.status === 'Fechada' ? 'bg-yellow-100 text-yellow-800' : 
                          oportunidade.status === 'Encerrada' ? 'bg-gray-100 text-gray-800' :
                          'bg-red-100 text-red-800'
                        }`}>
                          {oportunidade.status}
                        </span>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-cursor-text-secondary">
                        {oportunidade.total_recomendacoes || 0}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm">
                        <Link to={`${getBasePath()}/oportunidades/${oportunidade.id}`} className="text-cursor-primary hover:underline">
                          Detalhes
                        </Link>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default OportunidadesList;
